SELECT total_count AS total_individuals
FROM total_counts
WHERE age_group_id = 1 AND year = 2023;

SELECT total_count
FROM total_counts
WHERE year = 2023 AND source = 'census';

SELECT SUM(total_count) AS total_sum
FROM total_counts
WHERE year = 2023;

SELECT MIN(total_count) AS min_total_count
FROM total_counts
WHERE year = 2023;

SELECT MIN(count) AS min_count
FROM demographic_data
WHERE year = 2023;

SELECT MAX(total_count) AS max_total_count
FROM total_counts
WHERE year = 2023;

SELECT DISTINCT gender_id
FROM demographic_data
WHERE year = 2023;

SELECT total_count
FROM total_counts
WHERE age_group_id = 1 AND year = (SELECT MAX(year) FROM total_counts WHERE age_group_id = 1);
